157→                                                alt="profile"
158→                                            />
159→                                        </div>
160→                                        <p className={`mobile-navlink-label ${session ? 'mobile-navlink-label-active' : ''}`}>
161→                                            {link.label}
162→                                        </p>
163→                                    </div>
164→                                );
165→                            }
166→
167→                            return (
168→                                <div
169→                                    key={index}
170→                                    className="mobile-navlink-item"
171→                                    onClick={() => link.action(link.path)}
172→                                >
173→                                    <div className="mobile-navlink-icons">
174→                                        {link.icon(isActive)}
175→                                        {link.notifCount && (
